package com.socialblog.notification.domain;import jakarta.persistence.*;import java.time.Instant;import java.util.UUID;@Entity @Table(name="notifications",uniqueConstraints=@UniqueConstraint(name="uk_notification_event_recipient",columnNames={"source_event_id","recipient_id"}))public class Notification{@Id private UUID id;@Column(name="source_event_id",nullable=false)private UUID sourceEventId;@Column(name="recipient_id",nullable=false)private UUID recipientId;@Column(name="actor_id",nullable=false)private UUID actorId;@Enumerated(EnumType.STRING)@Column(nullable=false)private Type type;@Column(name="entity_type")private String entityType;@Column(name="entity_id")private UUID entityId;@Column(nullable=false,columnDefinition="TEXT")private String metadata;@Column(name="created_at",nullable=false)private Instant createdAt;@Column(name="read_at")private Instant readAt;protected Notification(){}public Notification(UUID source,UUID recipient,UUID actor,Type type,String entityType,UUID entityId,String metadata,Instant at){id=UUID.randomUUID();sourceEventId=source;recipientId=recipient;actorId=actor;this.type=type;this.entityType=entityType;this.entityId=entityId;this.metadata=metadata;createdAt=at;}public void markRead(){if(readAt==null)readAt=Instant.now();}public UUID getId(){return id;}public UUID getRecipientId(){return recipientId;}public UUID getActorId(){return actorId;}public Type getType(){return type;}public String getEntityType(){return entityType;}public UUID getEntityId(){return entityId;}public String getMetadata(){return metadata;}public Instant getCreatedAt(){return createdAt;}public Instant getReadAt(){return readAt;}public enum Type{NEW_FOLLOWER,NEW_COMMENT,NEW_REPLY,NEW_LIKE,NEW_ARTICLE}}
